const projects = [{
  name: 'Project Name',
  link: '#',
  language: 'Python',
  imageURL: './assets/myman.png',
  description: 'Lorem ipsum dolor sit amet, officia excepteur ex fugiat reprehenderit enim labore culpa sint ad nisi Lorem pariatur mollit ex esse exercitation amet. Nisi anim cupidatat excepteur officia. Reprehenderit nostrud nostrud ipsum Lorem est aliquip amet voluptate voluptate dolor minim nulla est proident. Nostrud officia pariatur ut officia. Sit irure elit esse ea nulla sunt ex occaecat reprehenderit commodo officia dolor Lorem duis laboris cupidatat officia voluptate. Culpa proident adipisicing id nulla nisi laboris ex in Lorem sunt duis officia eiusmod. Aliqua reprehenderit commodo ex non excepteur duis sunt velit enim. Voluptate laboris sint cupidatat ullamco ut ea consectetur et est culpa et culpa duis.'
}, {
  name: 'Project Name',
  link: '#',
  language: 'Python',
  imageURL: './assets/myman.png',
  description: 'Lorem ipsum dolor sit amet, officia excepteur ex fugiat reprehenderit enim labore culpa sint ad nisi Lorem pariatur mollit ex esse exercitation amet. Nisi anim cupidatat excepteur officia. Reprehenderit nostrud nostrud ipsum Lorem est aliquip amet voluptate voluptate dolor minim nulla est proident. Nostrud officia pariatur ut officia. Sit irure elit esse ea nulla sunt ex occaecat reprehenderit commodo officia dolor Lorem duis laboris cupidatat officia voluptate. Culpa proident adipisicing id nulla nisi laboris ex in Lorem sunt duis officia eiusmod. Aliqua reprehenderit commodo ex non excepteur duis sunt velit enim.'
}];

function Project({ name, link, language, imageURL, description }) {
  return (
    <a href={ link } className='rounded-md p-4 bg-gunmetal hover:bg-gunmetal-light grid gap-8'>
      <div className='flex flex-col'>
        <h1 className='text-xl font-[DrukWide]'> { name } </h1>
        <p className='text-md font-[DrukWide] pb-4'> { language } </p>
        <p> { description } </p>
      </div>
      <img className='max-w-64' src={ require(imageURL) } alt={ 'Image of ' + name } />
    </a>
  );
}

function Projects() {
  const projectItems = projects.map(project => 
  <li className='py-3'>
    <Project name={project.name} 
    link={project.link} 
    language={project.language}
    imageURL={project.imageURL} 
    description={project.description}/>
  </li>
  );

  return (
    <>
      <h1 className='text-3xl text-center text-stone-200 font-[DrukWide]'>
        Recent Projects
      </h1>
      <ul className='gap-8'>
        { projectItems }
      </ul>
    </>
  );
}

export default Projects;
